package com.example.lessondesign.bean; import javax.crypto.Mac; import javax.crypto.spec.SecretKeySpec; import java.nio.charset.StandardCharsets; import java.security.*; import org.apache.commons.codec.binary.Base64; public class ApiAuthAlgorithm { public String getSignature(String appId,String apiSecret,long ts){ try { String auth=md5(appId+ts); return hmacSHA1Encrypt(auth,apiSecret); } catch(Exception e){ return null; } } private String hmacSHA1Encrypt(String text,String key) throws Exception { SecretKeySpec spec=new SecretKeySpec(key.getBytes(StandardCharsets.UTF_8),"HmacSHA1"); Mac mac=Mac.getInstance("HmacSHA1"); mac.init(spec); return Base64.encodeBase64String(mac.doFinal(text.getBytes(StandardCharsets.UTF_8))); } private String md5(String text) throws Exception { MessageDigest md=MessageDigest.getInstance("MD5"); byte[] d=md.digest(text.getBytes(StandardCharsets.UTF_8)); StringBuilder sb=new StringBuilder(); for(byte b:d) sb.append(String.format("%02x",b)); return sb.toString(); } }